package com.yottastudios.ns.collabspace.spaceannouncement.task;

import com.yottastudios.ns.collabspace.spaceannouncement.service.ISpaceAnnouncementService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import net.javacrumbs.shedlock.spring.annotation.SchedulerLock;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

@Slf4j
@Component
public class SpaceAnnouncementExpireTask {

    @Resource
    private ISpaceAnnouncementService spaceAnnouncementService;

    /**
     * 每分钟检查是否有到期公告需要自动下线
     */
    @Scheduled(cron = "0 * * * * ?")
    @SchedulerLock(name = "spaceAnnouncementExpire", lockAtMostFor = "50s", lockAtLeastFor = "10s")
    public void checkExpiredAnnouncements() {
        spaceAnnouncementService.expireAnnouncements();
    }
}

