 36→@Slf4j
 37→@Service
 38→public class SpaceAnnouncementServiceImpl implements ISpaceAnnouncementService {
 39→
 40→    private static final DateTimeFormatter DATETIME_FORMAT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");
 41→    private static final DateTimeFormatter DATE_FORMAT = DateTimeFormatter.ofPattern("yyyy-MM-dd");
 42→    /** 默认有效期截止时间：当天 23:59 */
 43→    private static final LocalTime DEFAULT_EXPIRE_TIME = LocalTime.of(23, 59);
 44→
 45→    @Resource
 46→    private SpaceAnnouncementManager announcementManager;
 47→
 48→    @Resource
 49→    private SpaceAnnouncementReadRecordManager readRecordManager;
 50→
 51→    @Resource
 52→    private ControlTemplate controlTemplate;
 53→
 54→    @Resource
 55→    private ApitableGrpcClientServiceImpl apitableGrpcClientService;
 56→
 57→    @Resource
 58→    private RabbitMqSender rabbitMqSender;
 59→
 60→    @Override
 61→    @Transactional(rollbackFor = Exception.class)
 62→    public SpaceAnnouncementVo createAnnouncement(CreateSpaceAnnouncementRo ro) {
 63→        Long userId = SessionContext.getUserId();
 64→        // 空间站公告需要校验管理员权限
 65→        if (AnnouncementCategory.SPACE.getCode() == ro.getCategory()) {
 66→            if (ro.getSpaceId() == null || ro.getSpaceId().isBlank()) {
 67→                throw new BusinessException(SpaceException.UNAUTHORIZED);
 68→            }
 69→            controlTemplate.mustBeSpaceAdmin(userId, ro.getSpaceId());
 70→        }
 71→
 72→        // 获取发布人信息
 73→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
 74→        String publisherName = userInfo != null ? userInfo.getNickName() : "";
 75→
 76→        // 构建实体
 77→        SpaceAnnouncementEntity entity = new SpaceAnnouncementEntity();
 78→        entity.setSpaceId(ro.getSpaceId());
 79→        entity.setCategory(ro.getCategory());
 80→        entity.setTitle(ro.getTitle());
 81→        entity.setContent(ro.getContent());
 82→        entity.setIsPopup(ro.getIsPopup());
 83→        entity.setPublishType(ro.getPublishType());
 84→        entity.setPublisherId(userId);
 85→        entity.setPublisherName(publisherName);
 86→
 87→        boolean isScheduled = PublishType.SCHEDULED.getCode() == ro.getPublishType();
 88→
 89→        if (isScheduled) {
 90→            LocalDateTime scheduledTime = LocalDateTime.parse(ro.getScheduledPublishTime(), DATETIME_FORMAT);
 91→            entity.setScheduledPublishTime(scheduledTime);
 92→            entity.setStatus(SpaceAnnouncementStatus.PENDING.getCode());
 93→        } else {
 94→            // 立即发布：将同类型旧公告下线
 95→            offlineCurrentActive(ro.getCategory(), ro.getSpaceId());
 96→            entity.setStatus(SpaceAnnouncementStatus.ACTIVE.getCode());
 97→            entity.setPublishTime(LocalDateTime.now());
 98→        }
 99→
100→        // 有效期
101→        if (ro.getExpireTime() != null && !ro.getExpireTime().isBlank()) {
102→            entity.setExpireTime(parseExpireTime(ro.getExpireTime()));
103→        }
