  content: string;
}

// ─── 请求参数 ─────────────────────────────────────────────────────────────────

export interface ICreateAnnouncementParams {
  /** 1=空间站公告 */
  category: IAnnouncementCategory;
  /** 空间站公告必填 */
  spaceId?: string;
  title: string;
  content: string;
  isPopup: boolean;
  publishType: IPublishType;
  /** 定时发布必填，格式 yyyy-MM-dd HH:mm，需晚于当前时间 10 分钟 */
  scheduledPublishTime?: string | null;
  /** 有效期截止，null=永久有效 */
  expireTime?: string | null;
}

export interface IUpdateAnnouncementParams {
  id: string;
  title: string;
  content: string;
  isPopup: boolean;
  /** null 或空字符串=清除有效期（永久有效） */
  expireTime?: string | null;
}

// ─── 管理端接口 ───────────────────────────────────────────────────────────────

/** 接口1：发布公告 */
export const createSpaceAnnouncement = (params: ICreateAnnouncementParams) =>
  fetchData<ICreateAnnouncementParams, ISpaceAnnouncementVo>({
    url: '/api/v1/space-announcement/create',
    method: 'POST',
    data: params,
  });

/** 接口2：编辑当前生效公告 */
export const updateSpaceAnnouncement = (params: IUpdateAnnouncementParams) =>
  fetchData<IUpdateAnnouncementParams, null>({
    url: '/api/v1/space-announcement/update',
    method: 'POST',
    data: params,
  });

/** 接口3：下线公告 */
export const offlineSpaceAnnouncement = (id: string) =>
  fetchData<void, null>({
    url: `/api/v1/space-announcement/offline?id=${id}`,
    method: 'POST',
  });

/** 接口4：删除历史公告（软删除，仅 status=2 可删） */
export const deleteSpaceAnnouncement = (id: string) =>
  fetchData<void, null>({
    url: `/api/v1/space-announcement/delete?id=${id}`,
    method: 'POST',
  });

/** 接口5：获取当前生效公告（管理端） */
export const getSpaceAnnouncementActive = (spaceId: string) =>
  fetchData<void, ISpaceAnnouncementVo | null>({
    url: `/api/v1/space-announcement/active?category=1&spaceId=${spaceId}`,
  });

/** 接口6：获取待发布公告列表（管理端） */
export const getSpaceAnnouncementPending = (spaceId: string) =>
  fetchData<void, ISpaceAnnouncementVo[]>({
    url: `/api/v1/space-announcement/pending?category=1&spaceId=${spaceId}`,
  });

/** 接口7：获取历史公告列表（管理端） */
export const getSpaceAnnouncementHistory = (spaceId: string) =>
  fetchData<void, ISpaceAnnouncementVo[]>({
    url: `/api/v1/space-announcement/history?category=1&spaceId=${spaceId}`,
  });

/** 接口5b：获取当前生效平台公告（管理端） */
export const getPlatformAnnouncementActive = () =>
  fetchData<void, ISpaceAnnouncementVo | null>({
    url: '/api/v1/space-announcement/active?category=2',
  });

/** 接口6b：获取待发布平台公告列表（管理端） */
export const getPlatformAnnouncementPending = () =>
  fetchData<void, ISpaceAnnouncementVo[]>({
    url: '/api/v1/space-announcement/pending?category=2',
  });

/** 接口7b：获取历史平台公告列表（管理端） */
export const getPlatformAnnouncementHistory = () =>
  fetchData<void, ISpaceAnnouncementVo[]>({
    url: '/api/v1/space-announcement/history?category=2',
  });

// ─── 用户端接口 ───────────────────────────────────────────────────────────────

/** 接口8：获取横幅公告列表（用户端，最多2条） */
export const getSpaceAnnouncementBanner = (spaceId: string) =>
  fetchData<void, IBannerAnnouncementVo[]>({
    url: `/api/v1/space-announcement/banner?spaceId=${spaceId}`,
  });

/**
 * 接口9：获取公告详情（用户端）
 * 调用此接口会自动写入已读记录，弹窗不再重复出现
 */
export const getSpaceAnnouncementDetail = (id: string) =>
  fetchData<void, ISpaceAnnouncementVo | null>({
    url: `/api/v1/space-announcement/detail?id=${id}`,
  });

/** 接口10：获取未读弹窗公告（用户端，isPopup=true 且当前用户未读） */
export const getSpaceAnnouncementUnreadPopup = (spaceId: string) =>
  fetchData<void, IUnreadPopupVo[]>({
    url: `/api/v1/space-announcement/unread-popup?spaceId=${spaceId}`,
  });

