 89→          content: state.content,
 90→          isPopup: state.isPopup,
 91→          publishType: mode === 'scheduled' ? 1 : 0,
 92→          scheduledPublishTime: mode === 'scheduled' ? state.scheduledPublishTime : null,
 93→          expireTime: state.expireTime,
 94→        });
 95→      }
 96→      setEditorOpen(false);
 97→      setEditor(emptyEditor());
