363→              ))
364→            )}
365→      </div>
366→
367→      {/* REPLACE CONFIRM */}
368→      <Modal
369→        open={!!replaceTarget}
370→        title={t('spaceAnnouncementReplaceTitle')}
371→        okText={t('spaceAnnouncementConfirmReplace')}
372→        cancelText={t('cancel')}
373→        confirmLoading={saving}
374→        onOk={() => {
375→          setReplaceTarget(null);
376→          runSave(editor, pubMode);
377→        }}
378→        onCancel={() => setReplaceTarget(null)}
379→      >
380→        <Typography.Text>{t('spaceAnnouncementReplaceDesc')}</Typography.Text>
381→      </Modal>
382→
383→      {/* OFFLINE CONFIRM */}
384→      <Modal
385→        open={!!offlineTarget}
386→        title={null}
387→        okText={t('spaceAnnouncementConfirmOffline')}
388→        cancelText={t('cancel')}
389→        confirmLoading={offlining}
390→        onOk={() => offlineTarget && runOffline(offlineTarget)}
391→        onCancel={() => setOfflineTarget(null)}
392→        width={400}
393→        centered
394→      >
395→        <div className={styles.confirmModalBody}>
396→          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-info-bg)' }}>
397→            <svg
398→              width="22"
399→              height="22"
400→              viewBox="0 0 24 24"
401→              fill="none"
402→              stroke="var(--color-info)"
403→              strokeWidth="2"
404→            >
405→              <circle cx="12" cy="12" r="10" />
406→              <polyline points="8 12 12 16 16 12" />
407→              <line
408→                x1="12"
409→                y1="8"
410→                x2="12"
411→                y2="16"
412→              />
413→            </svg>
414→          </div>
415→          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementOfflineTitle')}</div>
416→          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementOfflineDesc')}</div>
417→        </div>
418→      </Modal>
419→
420→      {/* DELETE CONFIRM */}
421→      <Modal
422→        open={!!deleteTarget}
423→        title={null}
424→        okText={t('delete')}
425→        okButtonProps={{ danger: true }}
426→        cancelText={t('cancel')}
427→        confirmLoading={deleting}
428→        onOk={() => deleteTarget && runDelete(deleteTarget)}
