toolUseResult.originalFile:
import { useRequest } from 'ahooks';
import {
  Button,
  DatePicker,
  Flex,
  Input,
  Modal,
  Segmented,
  Space,
  Switch,
  Tag,
  Typography,
} from 'antd';
import dayjs from 'dayjs';
import React, { useCallback, useState } from 'react';
import { useParams } from 'react-router';

import { TipTapEditor } from '@/components/Common/TiptapEditor/TipTapEditor.tsx';
import { t } from '@/i18n';

import {
  createSpaceAnnouncement,
  deleteSpaceAnnouncement,
  getSpaceAnnouncementActive,
  getSpaceAnnouncementHistory,
  getSpaceAnnouncementPending,
  type ISpaceAnnouncementVo,
  offlineSpaceAnnouncement,
  updateSpaceAnnouncement,
} from './spaceAnnounce.api.ts';
import styles from './SpaceAnnouncement.module.css';

type PubMode = 'now' | 'scheduled';

interface IEditorState {
  title: string;
  content: string;
  expireTime: string | null;
  isPopup: boolean;
  scheduledPublishTime: string | null;
  /** editing existing active id; null = new */
  editingId: string | null;
}

const emptyEditor = (): IEditorState => ({
  title: '',
  content: '',
  expireTime: null,
  isPopup: false,
  scheduledPublishTime: null,
  editingId: null,
});

export const SpaceAnnouncement: React.FC = () => {
  const spaceId = useParams().spaceId!;

  const [editorOpen, setEditorOpen] = useState(false);
  const [editor, setEditor] = useState<IEditorState>(emptyEditor());
  const [pubMode, setPubMode] = useState<PubMode>('now');
  const [replaceTarget, setReplaceTarget] = useState<ISpaceAnnouncementVo | null>(null);
  const [offlineTarget, setOfflineTarget] = useState<ISpaceAnnouncementVo | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<ISpaceAnnouncementVo | null>(null);

  const { data: active, refresh: refreshActive } = useRequest(() => getSpaceAnnouncementActive(spaceId));
  const { data: pending = [], refresh: refreshPending } = useRequest(() => getSpaceAnnouncementPending(spaceId));
  const { data: history = [], refresh: refreshHistory } = useRequest(() => getSpaceAnnouncementHistory(spaceId));

  const refreshAll = useCallback(() => {
    refreshActive();
    refreshPending();
    refreshHistory();
  }, [refreshActive, refreshPending, refreshHistory]);

  const { loading: saving, runAsync: runSave } = useRequest(
    async (state: IEditorState, mode: PubMode) => {
      if (state.editingId) {
        await updateSpaceAnnouncement({
          id: state.editingId,
          title: state.title,
          content: state.content,
          isPopup: state.isPopup,
          expireTime: state.expireTime,
        });
        console.info('[lbl][2210-公告][SpaceAnnouncement][UPDATE] 编辑公告成功', { id: state.editingId });
      } else {
        await createSpaceAnnouncement({
          category: 1,
          spaceId,
          title: state.title,
          content: state.content,
          isPopup: state.isPopup,
          publishType: mode === 'scheduled' ? 1 : 0,
          scheduledPublishTime: mode === 'scheduled' ? state.scheduledPublishTime : null,
          expireTime: state.expireTime,
        });
        console.info('[lbl][2210-公告][SpaceAnnouncement][CREATE] 发布公告成功', { spaceId, mode });
      }
      setEditorOpen(false);
      setEditor(emptyEditor());
      refreshAll();
    },
    { manual: true },
  );

  const { loading: offlining, runAsync: runOffline } = useRequest(
    async (item: ISpaceAnnouncementVo) => {
      await offlineSpaceAnnouncement(item.id);
      setOfflineTarget(null);
      refreshAll();
    },
    { manual: true },
  );

  const { loading: deleting, runAsync: runDelete } = useRequest(
    async (item: ISpaceAnnouncementVo) => {
      await deleteSpaceAnnouncement(item.id);
      setDeleteTarget(null);
      refreshAll();
    },
    { manual: true },
  );

  const openCreate = () => {
    setEditor(emptyEditor());
    setPubMode('now');
    setEditorOpen(true);
  };

  const openEdit = (item: ISpaceAnnouncementVo) => {
    setEditor({
      title: item.title,
      content: item.content,
      expireTime: item.expireTime,
      isPopup: item.isPopup,
      scheduledPublishTime: item.scheduledPublishTime,
      editingId: item.id,
    });
    setPubMode('now');
    setEditorOpen(true);
  };

  const openRepublish = (item: ISpaceAnnouncementVo) => {
    setEditor({
      title: item.title,
      content: item.content,
      expireTime: item.expireTime,
      isPopup: item.isPopup,
      scheduledPublishTime: null,
      editingId: null,
    });
    setPubMode('now');
    setEditorOpen(true);
  };

  const handlePublish = () => {
    const { title, content, scheduledPublishTime } = editor;
    if (!title.trim() || !content.trim()) return;
    if (pubMode === 'scheduled' && !scheduledPublishTime) return;
    if (editor.editingId) {
      runSave(editor, pubMode);
      return;
    }
    if (active && pubMode === 'now') {
      setReplaceTarget(active);
    } else {
      runSave(editor, pubMode);
    }
  };

  const handlePubModeChange = useCallback((mode: PubMode) => {
    setPubMode(mode);
    if (mode === 'scheduled') {
      setEditor((prev) => ({
        ...prev,
        scheduledPublishTime: prev.scheduledPublishTime ?? dayjs().format('YYYY-MM-DD HH:mm'),
      }));
    }
  }, []);

  const handleCancelPending = (item: ISpaceAnnouncementVo) => {
    openRepublish(item);
    offlineSpaceAnnouncement(item.id).then(refreshAll);
  };

  const editorTitle = editor.editingId
    ? t('spaceAnnouncementEdit')
    : t('spaceAnnouncementCreate');

  return (
    <div className={styles.container}>
      {/* PAGE HEADER */}
      <div className={styles.pageHeader}>
        <div>
          <Typography.Title level={4} style={{ marginBottom: 2 }}>
            {t('spaceAnnouncement')}
          </Typography.Title>
          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
            {t('spaceAnnouncementDesc')}
          </Typography.Text>
        </div>
        <Button type="primary" onClick={openCreate}>
          + {t('spaceAnnouncementCreate')}
        </Button>
      </div>

      {/* EDITOR */}
      {editorOpen && (
        <div className={styles.section}>
          <div className={styles.sectionHeader}>
            <span className={styles.sectionTitle}>
              <span className={styles.dot} style={{ background: 'var(--color-primary)' }} />
              {editorTitle}
            </span>
            {editor.editingId && (
              <Tag color="processing">{t('spaceAnnouncementEditing')}</Tag>
            )}
          </div>
          <div className={styles.sectionBody}>
            <EditorPanel
              state={editor}
              onChange={setEditor}
              pubMode={pubMode}
              onPubModeChange={handlePubModeChange}
              isEditing={!!editor.editingId}
              onPublish={handlePublish}
              onCancel={() => {
                setEditorOpen(false);
                setEditor(emptyEditor());
              }}
              saving={saving}
            />
          </div>
        </div>
      )}

      {/* REALTIME PREVIEW */}
      {editorOpen && (
        <div className={styles.section}>
          <div className={styles.sectionHeader}>
            <span className={styles.sectionTitle}>
              <span className={styles.dot} style={{ background: '#10b981' }} />
              {t('spaceAnnouncementPreview')}
            </span>
          </div>
          <div className={styles.sectionBody}>
            <AnnouncementPreview title={editor.title} content={editor.content} popup={editor.isPopup} />
          </div>
        </div>
      )}

      {/* PENDING（待发布） */}
      {pending.length > 0 && (
        <div className={styles.section}>
          <div className={styles.sectionHeader}>
            <span className={styles.sectionTitle}>
              <span className={styles.dot} style={{ background: '#f59e0b' }} />
              {t('spaceAnnouncementScheduled')}
            </span>
          </div>
          <div className={styles.sectionBody}>
            <Space orientation="vertical" style={{ width: '100%' }} size={12}>
              {pending.map((item) => (
                <div key={item.id} className={styles.scheduledCard}>
                  <div className={styles.cardTitle}>{item.title}</div>
                  <div className={styles.cardMeta}>
                    <Tag color="orange">{t('spaceAnnouncementBadgeScheduled')}</Tag>
                    <Tag>{t('spaceAnnouncementScheduledAt')} {item.scheduledPublishTime}</Tag>
                    {item.expireTime && <Tag>{t('spaceAnnouncementExpireTo')} {dayjs(item.expireTime).format('YYYY-MM-DD')}</Tag>}
                    {item.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
                  </div>
                  <div
                    className={styles.scheduledCardBodyPreview}
                    dangerouslySetInnerHTML={{ __html: item.content }}
                  />
                  <div className={styles.cardActions}>
                    <Button size="small" onClick={() => handleCancelPending(item)}>
                      {t('spaceAnnouncementCancelAndReedit')}
                    </Button>
                    <Button size="small" danger onClick={() => setDeleteTarget(item)}>
                      {t('delete')}
                    </Button>
                  </div>
                </div>
              ))}
            </Space>
          </div>
        </div>
      )}

      {/* ACTIVE */}
      <div className={styles.section}>
        <div className={styles.sectionHeader}>
          <span className={styles.sectionTitle}>
            <span className={styles.dot} style={{ background: '#10b981' }} />
            {t('spaceAnnouncementActive')}
          </span>
        </div>
        <div className={styles.sectionBody}>
          {active
            ? (
                <div className={styles.activeCard}>
                  <div className={styles.cardTitle}>{active.title}</div>
                  <div className={styles.cardMeta}>
                    <Tag color="success">{t('spaceAnnouncementBadgeActive')}</Tag>
                    {active.isPopup && <Tag color="blue">{t('spaceAnnouncementPopup')}</Tag>}
                    {active.expireTime
                      ? <Tag color="warning">{t('spaceAnnouncementExpireTo')} {dayjs(active.expireTime).format('YYYY-MM-DD')}</Tag>
                      : <Tag>{t('spaceAnnouncementNeverExpire')}</Tag>}
                    <Tag>
                      {t('spaceAnnouncementPublishedAt')} {active.publishTime}
                      {active.publisherName && ` · ${active.publisherName}`}
                    </Tag>
                  </div>
                  <div
                    className={styles.cardBodyPreview}
                    dangerouslySetInnerHTML={{ __html: active.content }}
                  />
                  <div className={styles.cardActions}>
                    <Button size="small" onClick={() => openEdit(active)}>
                      {t('edit')}
                    </Button>
                    <Button size="small" onClick={() => setOfflineTarget(active)}>
                      {t('spaceAnnouncementOffline')}
                    </Button>
                  </div>
                </div>
              )
            : (
                <div className={styles.emptyTip}>{t('spaceAnnouncementNoActive')}</div>
              )}
        </div>
      </div>

      {/* HISTORY */}
      <div className={styles.section}>
        <div className={styles.sectionHeader}>
          <span className={styles.sectionTitle}>
            <span className={styles.dot} style={{ background: 'var(--color-text-quaternary)' }} />
            {t('spaceAnnouncementHistory')}
          </span>
        </div>
        {history.length === 0
          ? (
              <div className={styles.emptyTip}>{t('spaceAnnouncementNoHistory')}</div>
            )
          : (
              history.map((item) => (
                <div key={item.id} className={styles.historyItem}>
                  <div className={styles.historyInfo}>
                    <div className={styles.historyTitle}>{item.title}</div>
                    <div className={styles.historyMeta}>
                      {item.publishTime}
                      {item.expireTime ? ` · ${t('spaceAnnouncementExpireTo')} ${dayjs(item.expireTime).format('YYYY-MM-DD')}` : ''}
                    </div>
                  </div>
                  <div className={styles.historyActions}>
                    <Button size="small" onClick={() => openRepublish(item)}>
                      {t('spaceAnnouncementRepublish')}
                    </Button>
                    <Button size="small" danger onClick={() => setDeleteTarget(item)}>
                      {t('delete')}
                    </Button>
                  </div>
                </div>
              ))
            )}
      </div>

      {/* REPLACE CONFIRM */}
      <Modal
        open={!!replaceTarget}
        title={t('spaceAnnouncementReplaceTitle')}
        okText={t('spaceAnnouncementConfirmReplace')}
        cancelText={t('cancel')}
        confirmLoading={saving}
        onOk={() => {
          setReplaceTarget(null);
          runSave(editor, pubMode);
        }}
        onCancel={() => setReplaceTarget(null)}
      >
        <Typography.Text>{t('spaceAnnouncementReplaceDesc')}</Typography.Text>
      </Modal>

      {/* OFFLINE CONFIRM */}
      <Modal
        open={!!offlineTarget}
        title={null}
        okText={t('spaceAnnouncementConfirmOffline')}
        cancelText={t('cancel')}
        confirmLoading={offlining}
        onOk={() => offlineTarget && runOffline(offlineTarget)}
        onCancel={() => setOfflineTarget(null)}
        width={400}
        centered
      >
        <div className={styles.confirmModalBody}>
          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-info-bg)' }}>
            <svg
              width="22"
              height="22"
              viewBox="0 0 24 24"
              fill="none"
              stroke="var(--color-info)"
              strokeWidth="2"
            >
              <circle cx="12" cy="12" r="10" />
              <polyline points="8 12 12 16 16 12" />
              <line
                x1="12"
                y1="8"
                x2="12"
                y2="16"
              />
            </svg>
          </div>
          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementOfflineTitle')}</div>
          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementOfflineDesc')}</div>
        </div>
      </Modal>

      {/* DELETE CONFIRM */}
      <Modal
        open={!!deleteTarget}
        title={null}
        okText={t('delete')}
        okButtonProps={{ danger: true }}
        cancelText={t('cancel')}
        confirmLoading={deleting}
        onOk={() => deleteTarget && runDelete(deleteTarget)}
        onCancel={() => setDeleteTarget(null)}
        width={400}
        centered
      >
        <div className={styles.confirmModalBody}>
          <div className={styles.confirmModalIcon} style={{ background: 'var(--color-error-bg)' }}>
            <svg
              width="22"
              height="22"
              viewBox="0 0 24 24"
              fill="none"
              stroke="var(--color-error)"
              strokeWidth="2"
            >
              <polyline points="3 6 5 6 21 6" />
              <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2" />
            </svg>
          </div>
          <div className={styles.confirmModalTitle}>{t('spaceAnnouncementDeleteTitle')}</div>
          <div className={styles.confirmModalDesc}>{t('spaceAnnouncementDeleteDesc')}</div>
        </div>
      </Modal>
    </div>
  );
};

/* ────────────────────────────────────────────── */

interface IEditorPanelProps {
  state: IEditorState;
  onChange(s: IEditorState): void;
  pubMode: PubMode;
  onPubModeChange(m: PubMode): void;
  isEditing: boolean;
  onPublish(): void;
  onCancel(): void;
  saving: boolean;
}

const EditorPanel: React.FC<IEditorPanelProps> = ({
  state, onChange, pubMode, onPubModeChange, isEditing, onPublish, onCancel, saving,
}) => {
  const update = <K extends keyof IEditorState>(k: K, v: IEditorState[K]) =>
    onChange({ ...state, [k]: v });

  const publishLabel = isEditing
    ? t('spaceAnnouncementSave')
    : pubMode === 'scheduled'
      ? t('spaceAnnouncementPublishScheduled')
      : t('spaceAnnouncementPublish');

  return (
    <Flex vertical style={{ width: '100%' }} gap={16}>
      {/* Title */}
      <div>
        <Typography.Text
          strong
          style={{
            fontSize: 12,
            color: 'var(--color-text-secondary)',
            textTransform: 'uppercase',
            letterSpacing: '0.4px',
          }}
        >
          {t('spaceAnnouncementTitleLabel')}
          {' '}
          <span style={{ color: 'var(--color-error)' }}>*</span>
        </Typography.Text>
        <Input
          value={state.title}
          maxLength={100}
          showCount
          placeholder={t('spaceAnnouncementTitlePlaceholder')}
          onChange={(e) => update('title', e.target.value.replace(/[\r\n]/g, ''))}
          style={{ marginTop: 6 }}
        />
        <Typography.Text type="secondary" style={{ fontSize: 12, marginTop: 4, display: 'block' }}>
          {t('spaceAnnouncementTitleHint')}
        </Typography.Text>
      </div>

      {/* Content */}
      <div>
        <Typography.Text
          strong
          style={{
            fontSize: 12,
            color: 'var(--color-text-secondary)',
            textTransform: 'uppercase',
            letterSpacing: '0.4px',
          }}
        >
          {t('spaceAnnouncementContentLabel')}
          {' '}
          <span style={{ color: 'var(--color-error)' }}>*</span>
        </Typography.Text>
        <div className={styles.editorWrap} style={{ marginTop: 6 }}>
          <TipTapEditor
            value={state.content}
            onChange={(v) => update('content', v)}
            editable
            className="max-h-[200px]"
          />
        </div>
      </div>

      {/* Options row */}
      <div className="w-full flex">
        <div className="basis-1/2">
          <Typography.Text
            strong
            style={{
              fontSize: 12,
              color: 'var(--color-text-secondary)',
              textTransform: 'uppercase',
              letterSpacing: '0.4px',
              display: 'block',
              marginBottom: 6,
            }}
          >
            {t('spaceAnnouncementExpire')}
          </Typography.Text>
          <DatePicker
            value={state.expireTime ? dayjs(state.expireTime) : null}
            onChange={(_d, str) => update('expireTime', str as string || null)}
            placeholder={t('spaceAnnouncementNeverExpire')}
            format="YYYY-MM-DD"
          />
          <Typography.Text type="secondary" style={{ fontSize: 12, display: 'block', marginTop: 4 }}>
            {t('spaceAnnouncementExpireHint')}
          </Typography.Text>
        </div>
        <div className="basis-1/2">
          <Typography.Text
            strong
            style={{
              fontSize: 12,
              color: 'var(--color-text-secondary)',
              textTransform: 'uppercase',
              letterSpacing: '0.4px',
              display: 'block',
              marginBottom: 6,
            }}
          >
            {t('spaceAnnouncementPopupLabel')}
          </Typography.Text>
          <Space>
            <Switch
              size="small"
              checked={state.isPopup}
              onChange={(v) => update('isPopup', v)}
            />
            <Typography.Text style={{ fontSize: 13 }}>{t('spaceAnnouncementPopupHint')}</Typography.Text>
          </Space>
        </div>
      </div>

      <div>
        <Typography.Text
          strong
          style={{
            fontSize: 12,
            color: 'var(--color-text-secondary)',
            textTransform: 'uppercase',
            letterSpacing: '0.4px',
            display: 'block',
            marginBottom: 8,
          }}
        >
          {t('spaceAnnouncementPubMode')}
        </Typography.Text>
        <div className="flex items-center gap-4">
          <Segmented
            value={pubMode}
            onChange={(v) => onPubModeChange(v as PubMode)}
            options={[
              { label: t('spaceAnnouncementPubNow'), value: 'now' },
              { label: t('spaceAnnouncementPubScheduled'), value: 'scheduled' },
            ]}
          />
          {pubMode === 'scheduled' && (
            <Space>
              <DatePicker
                showTime={{ format: 'HH:mm', showSecond: false }}
                format="YYYY-MM-DD HH:mm"
                value={state.scheduledPublishTime ? dayjs(state.scheduledPublishTime) : null}
                onChange={(_d, str) => update('scheduledPublishTime', str as string || null)}
                disabledDate={(current) => current < dayjs().startOf('day')}
                disabledTime={(date) => {
                  const min = dayjs().add(10, 'minute');
                  if (!date || !date.isSame(dayjs(), 'day')) return {};
                  return {
                    disabledHours: () => Array.from({ length: min.hour() }, (_, i) => i),
                    disabledMinutes: (h) => {
                      if (h < min.hour()) return Array.from({ length: 60 }, (_, i) => i);
                      if (h === min.hour()) return Array.from({ length: min.minute() + 1 }, (_, i) => i);
                      return [];
                    },
                  };
                }}
              />
              <Typography.Text type="secondary" style={{ fontSize: 12 }}>
                {t('spaceAnnouncementScheduledHint')}
              </Typography.Text>
            </Space>
          )}
        </div>
      </div>

      {/* Actions */}
      <div className={styles.actionBar}>
        <Button onClick={onCancel}>{t('cancel')}</Button>
        <Button
          type="primary"
          loading={saving}
          disabled={!state.title.trim() || !state.content.trim()}
          onClick={onPublish}
        >
          {publishLabel}
        </Button>
      </div>
    </Flex>
  );
};

/* ────────────────────────────────────────────── */

interface IAnnouncementPreviewProps {
  title: string;
  content: string;
  popup: boolean;
}

const AnnouncementPreview: React.FC<IAnnouncementPreviewProps> = ({ title, content, popup }) => (
  <Flex vertical style={{ width: '100%' }} gap={12}>
    <div className={styles.previewLabel}>{t('spaceAnnouncementPreviewBanner')}</div>
    <div className={styles.previewBanner}>
      <svg
        width="15"
        height="15"
        viewBox="0 0 24 24"
        fill="none"
        stroke="var(--color-primary)"
        strokeWidth="2"
      >
        <path d="M18 8h1a4 4 0 0 1 0 8h-1" />
        <path d="M2 8h16v9a4 4 0 0 1-4 4H6a4 4 0 0 1-4-4V8z" />
        <line
          x1="6"
          y1="1"
          x2="6"
          y2="4"
        />
        <line
          x1="10"
          y1="1"
          x2="10"
          y2="4"
        />
        <line
          x1="14"
          y1="1"
          x2="14"
          y2="4"
        />
      </svg>
      {title
        ? <span className={styles.previewBannerText}>{title}</span>
        : <span className={styles.previewBannerPlaceholder}>{t('spaceAnnouncementPreviewBannerPh')}</span>}
      <div className={styles.previewBannerActions}>
        <Typography.Link style={{ fontSize: 12 }}>{t('spaceAnnouncementViewDetail')}</Typography.Link>
        <span style={{ color: 'var(--color-primary)', cursor: 'pointer' }}>×</span>
      </div>
    </div>

    <div className={styles.previewLabel}>{t('spaceAnnouncementPreviewPopup')}</div>
    {popup
      ? (
          <div className={styles.popupPreviewWrap}>
            <div className={styles.popupOverlay} />
            <div className={styles.popupCard}>
              <div className={styles.popupCardTitle}>
                {title || <span style={{ color: 'var(--color-text-quaternary)', fontStyle: 'italic', fontWeight: 400 }}>{t('spaceAnnouncementTitlePlaceholder')}</span>}
              </div>
              <div
                className={styles.popupCardBody}
                dangerouslySetInnerHTML={{
                  __html: content || `<span style="color:var(--color-text-quaternary);font-style:italic">${t('spaceAnnouncementContentPlaceholder')}</span>`,
                }}
              />
              <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                <Button type="primary" size="small">{t('spaceAnnouncementGotIt')}</Button>
              </div>
            </div>
          </div>
        )
      : (
          <div className={styles.popupOff}>{t('spaceAnnouncementPopupOffHint')}</div>
        )}
  </Flex>
);

