package com.yottastudios.ns.collabspace.spaceannouncement.controller;

import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.spaceannouncement.ro.CreateSpaceAnnouncementRo;
import com.yottastudios.ns.collabspace.spaceannouncement.ro.UpdateSpaceAnnouncementRo;
import com.yottastudios.ns.collabspace.spaceannouncement.service.ISpaceAnnouncementService;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.ActiveAnnouncementVo;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.SpaceAnnouncementVo;
import com.yottastudios.ns.collabspace.spaceannouncement.vo.UnreadPopupAnnouncementVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@Slf4j
@RestController
@Tag(name = "Space Announcement")
@ApiResource(path = "/space-announcement")
public class SpaceAnnouncementController {

    @Resource
    private ISpaceAnnouncementService spaceAnnouncementService;

    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "创建/发布公告")
    public ResponseData<SpaceAnnouncementVo> createAnnouncement(@RequestBody @Valid CreateSpaceAnnouncementRo ro) {
        SpaceAnnouncementVo vo = spaceAnnouncementService.createAnnouncement(ro);
        return ResponseData.success(vo);
    }

    @PostResource(path = "/update", requiredPermission = false)
    @Operation(summary = "编辑当前生效公告")
    public ResponseData<Void> updateAnnouncement(@RequestBody @Valid UpdateSpaceAnnouncementRo ro) {
        spaceAnnouncementService.updateAnnouncement(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/offline", requiredPermission = false)
    @Operation(summary = "下线公告")
    public ResponseData<Void> offlineAnnouncement(@RequestParam @Parameter(description = "公告ID") Long id) {
        spaceAnnouncementService.offlineAnnouncement(id);
        return ResponseData.success();
    }

    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "删除历史公告（软删除）")
    public ResponseData<Void> deleteAnnouncement(@RequestParam @Parameter(description = "公告ID") Long id) {
        spaceAnnouncementService.deleteAnnouncement(id);
        return ResponseData.success();
    }

    @GetResource(path = "/active", requiredPermission = false)
    @Operation(summary = "获取当前生效公告（管理端）")
    public ResponseData<SpaceAnnouncementVo> getActiveAnnouncement(
            @RequestParam @Parameter(description = "分类：1=空间站,2=平台") Integer category,
            @RequestParam(required = false) @Parameter(description = "空间站ID") String spaceId) {
        SpaceAnnouncementVo vo = spaceAnnouncementService.getActiveAnnouncement(category, spaceId);
        return ResponseData.success(vo);
    }

    @GetResource(path = "/pending", requiredPermission = false)
    @Operation(summary = "获取待发布公告列表（管理端）")
    public ResponseData<List<SpaceAnnouncementVo>> getPendingAnnouncements(
            @RequestParam @Parameter(description = "分类") Integer category,
            @RequestParam(required = false) @Parameter(description = "空间站ID") String spaceId) {
        List<SpaceAnnouncementVo> list = spaceAnnouncementService.getPendingAnnouncements(category, spaceId);
        return ResponseData.success(list);
    }

    @GetResource(path = "/history", requiredPermission = false)
    @Operation(summary = "获取历史公告列表（管理端）")
    public ResponseData<List<SpaceAnnouncementVo>> getHistoryAnnouncements(
            @RequestParam @Parameter(description = "分类") Integer category,
            @RequestParam(required = false) @Parameter(description = "空间站ID") String spaceId) {
        List<SpaceAnnouncementVo> list = spaceAnnouncementService.getOfflineAnnouncements(category, spaceId);
        return ResponseData.success(list);
    }

    @GetResource(path = "/banner", requiredPermission = false)
    @Operation(summary = "获取横幅公告（用户端，最多2条）")
    public ResponseData<List<ActiveAnnouncementVo>> getBannerAnnouncements(
            @RequestParam @Parameter(description = "空间站ID") String spaceId) {
        List<ActiveAnnouncementVo> list = spaceAnnouncementService.getBannerAnnouncements(spaceId);
        return ResponseData.success(list);
    }

    @GetResource(path = "/detail", requiredPermission = false)
    @Operation(summary = "获取公告详情（用户端，同时记录已读）")
    public ResponseData<SpaceAnnouncementVo> getAnnouncementDetail(
            @RequestParam @Parameter(description = "公告ID") Long id) {
        SpaceAnnouncementVo vo = spaceAnnouncementService.getAnnouncementDetail(id);
        return ResponseData.success(vo);
    }

    @GetResource(path = "/unread-popup", requiredPermission = false)
    @Operation(summary = "获取未读弹窗公告（用户端）")
    public ResponseData<List<UnreadPopupAnnouncementVo>> getUnreadPopupAnnouncements(
            @RequestParam @Parameter(description = "空间站ID") String spaceId) {
        List<UnreadPopupAnnouncementVo> list = spaceAnnouncementService.getUnreadPopupAnnouncements(spaceId);
        return ResponseData.success(list);
    }
}

