public enum AnnouncementCategory {
    SPACE(1, "空间站公告"),
    PLATFORM(2, "平台公告");

    private final int code;
    private final String desc;

    public static AnnouncementCategory fromCode(int code) {
        for (AnnouncementCategory c : values()) {
            if (c.code == code) return c;
        }
        throw new IllegalArgumentException("Unknown AnnouncementCategory code: " + code);
    }
}

