 768→// ── 维度 5：注入防护 ──
 769→async function test_注入防护() {
 770→  console.log('\n🛡️ 维度5: 注入防护 + 特殊字符');
 771→
 772→  // title 特殊字符
 773→  const specialChars = [
 774→    '<script>alert(1)</script>',
 775→    "' OR 1=1 --",
 776→    '"; DROP TABLE collabspace_space_announcement;',
 777→    '&&||',
 778→    '🎉🎊😀',
 779→    '<img src=x onerror=alert(1)>',
 780→    '${7*7}',
 781→    '{{7*7}}',
 782→    '\'; WAITFOR DELAY \'0:0:5\' --',
 783→  ];
 784→  for (const ch of specialChars) {
 785→    const res = await POST('/space-announcement/create', makeCreateRo({ title: `注入测试${ch.slice(0, 15)}` }));
 786→    assert(`title 含 "${ch.slice(0, 20)}" 不报500`,
 787→      res.success === true || (res.code != null && res.code !== 500), res);
 788→    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
 789→  }
 790→
 791→  // content XSS
 792→  const xssPayloads = [
 793→    '<img src=x onerror=alert(document.cookie)>',
 794→    '<svg onload=alert(1)>',
 795→    '<iframe src="javascript:alert(1)">',
 796→    '<a href="javascript:void(0)" onclick="alert(1)">click</a>',
 797→  ];
 798→  for (const xss of xssPayloads) {
 799→    const res = await POST('/space-announcement/create', makeCreateRo({ content: xss }));
 800→    assert(`content XSS "${xss.slice(0, 25)}" 不报500`,
 801→      res.success === true || (res.code != null && res.code !== 500), res);
 802→    if (res.success && res.data?.id) cleanupIds.push(String(res.data.id));
 803→  }
 804→
 805→  // spaceId SQL 注入
 806→  const sqlInjections = ["' OR 1=1 --", "1; DROP TABLE xxx;", "' UNION SELECT 1,2,3 --"];
 807→  for (const inj of sqlInjections) {
 808→    const res = await GET(`/space-announcement/banner?spaceId=${encodeURIComponent(inj)}`);
 809→    assert(`spaceId 注入 "${inj.slice(0, 20)}" 不报500`,
 810→      res.success === true || (res.code != null && res.code !== 500), res);
 811→  }
 812→}
