293→    private void sendDelayedMessage(Long announcementId, LocalDateTime scheduledTime) {
294→        long delay = Duration.between(LocalDateTime.now(), scheduledTime).toMillis();
295→        if (delay < 0) delay = 0;
296→        // RabbitMqSender.sendDelayedMessage takes Object, pass String directly
297→        rabbitMqSender.sendDelayedMessage(
298→                QueueConfig.SPACE_ANNOUNCEMENT_EXCHANGE,
299→                QueueConfig.SPACE_ANNOUNCEMENT_KEY,
300→                announcementId.toString(), delay);
301→        log.info("[lbl][2210-公告][Announcement][MQ] 延迟消息已发送, id={}, delay={}ms", announcementId, delay);
302→    }
