326→                .publishTime(entity.getPublishTime())
327→                .expireTime(entity.getExpireTime())
328→                .offlineTime(entity.getOfflineTime())
329→                .publisherId(entity.getPublisherId())
330→                .publisherName(entity.getPublisherName())
331→                .createdAt(entity.getCreatedAt())
332→                .build();
333→    }
