package com.yottastudios.ns.collabspace.spaceannouncement.entity;

import com.baomidou.mybatisplus.annotation.TableName;
import com.yottastudios.ns.collabspace.core.entity.BaseEntity;
import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.EqualsAndHashCode;
import lombok.NoArgsConstructor;
import lombok.experimental.Accessors;
import lombok.experimental.SuperBuilder;

import java.io.Serial;
import java.io.Serializable;
import java.time.LocalDateTime;

@EqualsAndHashCode(callSuper = true)
@Data
@NoArgsConstructor
@AllArgsConstructor
@Accessors(chain = true)
@SuperBuilder
@TableName(keepGlobalPrefix = true, value = "space_announcement", autoResultMap = true)
public class SpaceAnnouncementEntity extends BaseEntity implements Serializable {

    @Serial
    private static final long serialVersionUID = 1L;

    private String spaceId;
    private Integer category;
    private String title;
    private String content;
    private Integer status;
    private Integer publishType;
    private Boolean isPopup;
    private LocalDateTime scheduledPublishTime;
    private LocalDateTime publishTime;
    private LocalDateTime expireTime;
    private LocalDateTime offlineTime;
    private Long publisherId;
    private String publisherName;
}

